"use strict";

// ---- contribution-graph.ts ----
async function fetchContributionGraph(username, token) {
  const query = `
    query($login: String!) {
      user(login: $login) {
        contributionsCollection {
          contributionCalendar {
            totalContributions
            weeks {
              contributionDays {
                date
                contributionCount
                contributionLevel
              }
            }
          }
        }
      }
    }
  `;

  const response = await fetch("https://api.github.com/graphql", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ query, variables: { login: username } }),
  });

  if (!response.ok) {
    throw new Error(`GitHub API error: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();

  if (data.errors) {
    throw new Error(`GraphQL error: ${JSON.stringify(data.errors)}`);
  }

  const calendar = data.data.user.contributionsCollection.contributionCalendar;

  const levelMap = {
    NONE: 0,
    FIRST_QUARTILE: 1,
    SECOND_QUARTILE: 2,
    THIRD_QUARTILE: 3,
    FOURTH_QUARTILE: 4,
  };

  return {
    totalContributions: calendar.totalContributions,
    weeks: calendar.weeks.map((week) => ({
      days: week.contributionDays.map((day) => ({
        date: day.date,
        count: day.contributionCount,
        level: levelMap[day.contributionLevel] ?? 0,
      })),
    })),
  };
}

// ---- cat-animator.ts ----
const CELL_SIZE = 11;
const CELL_GAP = 3;
const STEP = CELL_SIZE + CELL_GAP;
const GRID_TOP = 30;
const GRID_LEFT = 40;

const LEVEL_COLORS_LIGHT = ["#ebedf0", "#9be9a8", "#40c463", "#30a14e", "#216e39"];
const LEVEL_COLORS_DARK  = ["#161b22", "#0e4429", "#006d32", "#26a641", "#39d353"];

function buildCatHead(state, facingLeft) {
  const flip = facingLeft ? 'transform="scale(-1,1) translate(-20,0)"' : '';

  let eyes, mouth, extra = "";

  switch (state) {
    case "eating":
      eyes = `<circle cx="7" cy="9" r="1.5" fill="#222"/><circle cx="13" cy="9" r="1.5" fill="#222"/>`;
      mouth = `<path d="M7 13 Q10 16 13 13" stroke="#222" fill="none" stroke-width="1.5"/><circle cx="10" cy="14.5" r="2" fill="#ffd700" opacity="0.6"/>`;
      break;
    case "sleeping":
      eyes = `<line x1="5.5" y1="9" x2="8.5" y2="9" stroke="#222" stroke-width="1.5" stroke-linecap="round"/><line x1="11.5" y1="9" x2="14.5" y2="9" stroke="#222" stroke-width="1.5" stroke-linecap="round"/>`;
      mouth = `<path d="M8 13 Q10 14 12 13" stroke="#222" fill="none" stroke-width="1"/>`;
      extra = `<text x="14" y="7" font-size="6" fill="#888">z</text><text x="18" y="4" font-size="4.5" fill="#888" opacity="0.6">z</text>`;
      break;
    case "pooping":
      eyes = `<path d="M5.5 9 Q7 7.5 8.5 9" stroke="#222" fill="none" stroke-width="1.5"/><path d="M11.5 9 Q13 7.5 14.5 9" stroke="#222" fill="none" stroke-width="1.5"/>`;
      mouth = `<path d="M8 13 Q10 12 12 13" stroke="#222" fill="none" stroke-width="1"/>`;
      extra = `<text x="-4" y="22" font-size="8">💩</text>`;
      break;
    case "dead":
      eyes = `<text x="4.5" y="12" font-size="5" fill="#222">×</text><text x="10.5" y="12" font-size="5" fill="#222">×</text>`;
      mouth = `<path d="M8 14 Q10 12 12 14" stroke="#222" fill="none" stroke-width="1"/>`;
      break;
    default: // walking
      eyes = `<circle cx="7" cy="9" r="1.5" fill="#222"/><circle cx="13" cy="9" r="1.5" fill="#222"/>`;
      mouth = `<path d="M8 13 Q10 15 12 13" stroke="#222" fill="none" stroke-width="1.2"/>`;
  }

  const whiskers = `
    <line x1="1" y1="11" x2="7" y2="12" stroke="#ccc" stroke-width="0.7"/>
    <line x1="1" y1="13" x2="7" y2="13" stroke="#ccc" stroke-width="0.7"/>
    <line x1="13" y1="12" x2="19" y2="11" stroke="#ccc" stroke-width="0.7"/>
    <line x1="13" y1="13" x2="19" y2="13" stroke="#ccc" stroke-width="0.7"/>`;

  return `<g ${flip}>
    <ellipse cx="10" cy="11" rx="9" ry="8.5" fill="#FFD700" stroke="#E8C000" stroke-width="0.5"/>
    <polygon points="2,5 0,0 6,3" fill="#FFD700" stroke="#E8C000" stroke-width="0.5"/>
    <polygon points="2.5,4.5 1,1 5.5,3" fill="#FFB6C1"/>
    <polygon points="18,5 20,0 14,3" fill="#FFD700" stroke="#E8C000" stroke-width="0.5"/>
    <polygon points="17.5,4.5 19,1 14.5,3" fill="#FFB6C1"/>
    ${eyes}
    <polygon points="10,12 9,13 11,13" fill="#FF9999"/>
    ${whiskers}
    ${mouth}
    ${extra}
  </g>`;
}

function buildRatHead(facingLeft) {
  const flip = facingLeft ? 'transform="scale(-1,1) translate(-20,0)"' : '';
  return `<g ${flip}>
    <ellipse cx="10" cy="12" rx="8" ry="7" fill="#A0A0A0" stroke="#888" stroke-width="0.5"/>
    <circle cx="4" cy="5" r="4" fill="#C0C0C0" stroke="#888" stroke-width="0.5"/>
    <circle cx="4" cy="5" r="2.5" fill="#FFAAAA"/>
    <circle cx="16" cy="5" r="4" fill="#C0C0C0" stroke="#888" stroke-width="0.5"/>
    <circle cx="16" cy="5" r="2.5" fill="#FFAAAA"/>
    <circle cx="7" cy="10" r="1.5" fill="#FF4444"/>
    <circle cx="13" cy="10" r="1.5" fill="#FF4444"/>
    <circle cx="7.5" cy="9.5" r="0.5" fill="#fff"/>
    <circle cx="13.5" cy="9.5" r="0.5" fill="#fff"/>
    <ellipse cx="10" cy="14" rx="3" ry="2" fill="#CCC"/>
    <circle cx="10" cy="13.5" r="1" fill="#FF9999"/>
    <line x1="2" y1="13" x2="7" y2="14" stroke="#999" stroke-width="0.6"/>
    <line x1="2" y1="15" x2="7" y2="14.5" stroke="#999" stroke-width="0.6"/>
    <line x1="13" y1="14" x2="18" y2="13" stroke="#999" stroke-width="0.6"/>
    <line x1="13" y1="14.5" x2="18" y2="15" stroke="#999" stroke-width="0.6"/>
  </g>`;
}

function buildFish(level, colors) {
  const col = colors[level] ?? colors[1];
  return `<g>
    <ellipse cx="5.5" cy="5.5" rx="4.5" ry="3" fill="${col}" opacity="0.95"/>
    <polygon points="0,3.5 0,7.5 -3,5.5" fill="${col}" opacity="0.8"/>
    <circle cx="7" cy="5" r="1" fill="white"/>
    <circle cx="7.2" cy="5" r="0.5" fill="#333"/>
    <path d="M4 3 Q6 1 8 3" stroke="${col}" fill="none" stroke-width="0.8" opacity="0.7"/>
  </g>`;
}

function planCatPath(cells) {
  const active = cells.filter(c => c.level > 0);
  return [...active].sort((a, b) =>
    a.weekIndex !== b.weekIndex ? a.weekIndex - b.weekIndex : a.dayIndex - b.dayIndex
  );
}

function generateRatPath(weekCount, seed, totalDuration) {
  const frames = [];
  const points = 20;
  for (let i = 0; i <= points; i++) {
    const t = (i / points) * totalDuration;
    const phase = (i / points) * Math.PI * 4 + seed * Math.PI;
    const x = GRID_LEFT + Math.abs(Math.sin(phase * 0.7 + seed)) * (weekCount - 4) * STEP;
    const y = GRID_TOP + ((Math.sin(phase + seed * 2) + 1) / 2) * 5 * STEP;
    const prevPhase = ((i-1) / points) * Math.PI * 4 + seed * Math.PI;
    const prevX = i > 0 ? GRID_LEFT + Math.abs(Math.sin(prevPhase * 0.7 + seed)) * (weekCount - 4) * STEP : x;
    frames.push({ t, x, y, facingLeft: x < prevX });
  }
  return frames;
}

function generateCatSVG(graph, username, theme = "github") {
  const isDark = theme === "github-dark";
  const levelColors = isDark ? LEVEL_COLORS_DARK : LEVEL_COLORS_LIGHT;
  const bgColor = isDark ? "#0d1117" : "#ffffff";
  const textColor = isDark ? "#c9d1d9" : "#24292f";
  const borderColor = isDark ? "#30363d" : "#d0d7de";

  const weeks = graph.weeks;
  const svgWidth = GRID_LEFT + weeks.length * STEP + 20;
  const svgHeight = GRID_TOP + 7 * STEP + 60;

  // Build cell data
  const cells = [];
  weeks.forEach((week, wi) => {
    week.days.forEach((day, di) => {
      cells.push({
        weekIndex: wi, dayIndex: di,
        x: GRID_LEFT + wi * STEP,
        y: GRID_TOP + di * STEP,
        level: day.level,
        date: day.date,
      });
    });
  });

  const eatPath = planCatPath(cells);

  // Timing
  const MOVE_DURATION = 400;
  const EAT_DURATION = 300;
  const POOP_DURATION = 800;
  const SLEEP_DURATION = 3000;

  const keyframes = [];
  let time = 0;
  let eatCount = 0;
  let prevX = GRID_LEFT;
  const poops = [];

  keyframes.push({ t: 0, catX: prevX - STEP, catY: GRID_TOP + 3 * STEP, state: "walking", facingLeft: false, eatenUpTo: 0 });

  for (let i = 0; i < eatPath.length; i++) {
    const cell = eatPath[i];
    const dx = cell.x - prevX;

    time += MOVE_DURATION;
    keyframes.push({ t: time, catX: cell.x, catY: cell.y, state: "walking", facingLeft: dx < 0, eatenUpTo: eatCount });

    time += EAT_DURATION;
    eatCount++;
    keyframes.push({ t: time, catX: cell.x, catY: cell.y, state: "eating", facingLeft: dx < 0, eatenUpTo: eatCount });

    if (eatCount % 3 === 0) {
      const poopX = cell.x + (dx >= 0 ? -STEP : STEP);
      poops.push({ t: time, x: poopX, y: cell.y });

      time += POOP_DURATION;
      keyframes.push({ t: time, catX: cell.x, catY: cell.y, state: "pooping", facingLeft: dx < 0, eatenUpTo: eatCount });

      time += SLEEP_DURATION;
      keyframes.push({ t: time, catX: cell.x, catY: cell.y, state: "sleeping", facingLeft: dx < 0, eatenUpTo: eatCount });

      time += 300;
      keyframes.push({ t: time, catX: cell.x, catY: cell.y, state: "walking", facingLeft: dx < 0, eatenUpTo: eatCount });
    }

    prevX = cell.x;
  }

  time += 1000;
  const totalDuration = time + 500;
  const durS = (totalDuration / 1000).toFixed(2);

  // Month labels
  const monthLabels = [];
  let lastMonth = -1;
  weeks.forEach((week, wi) => {
    const firstDay = week.days.find(d => d.date);
    if (!firstDay) return;
    const month = new Date(firstDay.date).getMonth();
    if (month !== lastMonth) {
      const monthName = new Date(firstDay.date).toLocaleString("default", { month: "short" });
      monthLabels.push(`<text x="${GRID_LEFT + wi * STEP}" y="${GRID_TOP - 5}" font-size="9" fill="${isDark ? "#8b949e" : "#57606a"}" font-family="monospace">${monthName}</text>`);
      lastMonth = month;
    }
  });

  const dayLabels = ["", "Mon", "", "Wed", "", "Fri", ""].map((d, i) =>
    d ? `<text x="${GRID_LEFT - 5}" y="${GRID_TOP + i * STEP + 9}" font-size="8" text-anchor="end" fill="${isDark ? "#8b949e" : "#57606a"}" font-family="monospace">${d}</text>` : ""
  ).join("\n");

  // Grid cells
  const xKT_all = keyframes.map(kf => (kf.t / totalDuration).toFixed(4)).join(";");

  const gridCells = cells.map(cell => {
    if (cell.level === 0) {
      return `<rect x="${cell.x}" y="${cell.y}" width="${CELL_SIZE}" height="${CELL_SIZE}" rx="2" fill="${levelColors[0]}" stroke="${borderColor}" stroke-width="0.3"/>`;
    }

    const eatIndex = eatPath.findIndex(e => e.date === cell.date);
    if (eatIndex === -1) {
      return `<rect x="${cell.x}" y="${cell.y}" width="${CELL_SIZE}" height="${CELL_SIZE}" rx="2" fill="${levelColors[0]}" stroke="${borderColor}" stroke-width="0.3"/>`;
    }

    const eatKF = keyframes.find(kf => kf.eatenUpTo === eatIndex + 1 && kf.state === "eating");
    const eatT = eatKF ? eatKF.t : totalDuration;

    // Build opacity keyTimes matching all keyframes
    const opacities = keyframes.map(kf => kf.t < eatT ? "1" : "0").join(";");

    return `<g>
      <rect x="${cell.x}" y="${cell.y}" width="${CELL_SIZE}" height="${CELL_SIZE}" rx="2" fill="${levelColors[0]}" stroke="${borderColor}" stroke-width="0.3"/>
      <g transform="translate(${cell.x + 1},${cell.y + 1})">
        ${buildFish(cell.level, levelColors)}
        <animate attributeName="opacity" values="${opacities}" keyTimes="${xKT_all}" dur="${durS}s" repeatCount="indefinite" calcMode="discrete"/>
      </g>
    </g>`;
  }).join("\n");

  // Poops
  const poopsSVG = poops.map(p => {
    const showKT = (p.t / totalDuration).toFixed(4);
    const opacities = keyframes.map(kf => kf.t >= p.t ? "1" : "0").join(";");
    return `<g transform="translate(${p.x + 5},${p.y + 8})">
      <text x="0" y="0" font-size="9" text-anchor="middle">💩</text>
      <animate attributeName="opacity" values="${opacities}" keyTimes="${xKT_all}" dur="${durS}s" repeatCount="indefinite" calcMode="discrete"/>
    </g>`;
  }).join("\n");

  // Cat states (5 layers, only one visible at a time)
  const CAT_STATES = ["walking", "eating", "pooping", "sleeping", "dead"];
  const catStateLayers = CAT_STATES.map(state => {
    const opacities = keyframes.map(kf => kf.state === state ? "1" : "0").join(";");
    return `<g opacity="0">
      ${buildCatHead(state, false)}
      <animate attributeName="opacity" values="${opacities}" keyTimes="${xKT_all}" dur="${durS}s" repeatCount="indefinite" calcMode="discrete"/>
    </g>`;
  }).join("\n");

  const catCoords = keyframes.map(kf => `${kf.catX},${kf.catY}`).join(";");

  const catSVG = `<g>
    <animateTransform attributeName="transform" type="translate"
      values="${catCoords}"
      keyTimes="${xKT_all}"
      dur="${durS}s"
      repeatCount="indefinite"
      calcMode="linear"/>
    ${catStateLayers}
  </g>`;

  // Rats
  const rat1 = generateRatPath(weeks.length, 0, totalDuration);
  const rat2 = generateRatPath(weeks.length, 1, totalDuration);
  const ratsSVG = [rat1, rat2].map((path, ri) => {
    const xKT = path.map(f => (f.t / totalDuration).toFixed(4)).join(";");
    const coords = path.map(f => `${f.x},${f.y}`).join(";");
    return `<g>
      <animateTransform attributeName="transform" type="translate"
        values="${coords}"
        keyTimes="${xKT}"
        dur="${durS}s"
        repeatCount="indefinite"
        calcMode="linear"/>
      ${buildRatHead(false)}
    </g>`;
  }).join("\n");

  return `<svg xmlns="http://www.w3.org/2000/svg" width="${svgWidth}" height="${svgHeight}" viewBox="0 0 ${svgWidth} ${svgHeight}">
  <!-- Background -->
  <rect width="${svgWidth}" height="${svgHeight}" rx="6" fill="${bgColor}" stroke="${borderColor}" stroke-width="1"/>

  <!-- Title -->
  <text x="${svgWidth / 2}" y="16" font-size="12" text-anchor="middle" fill="${textColor}" font-family="monospace" font-weight="bold">🐱 ${username}'s contribution cat</text>

  <!-- Month labels -->
  ${monthLabels.join("\n")}

  <!-- Day labels -->
  ${dayLabels}

  <!-- Grid (fish dots) -->
  ${gridCells}

  <!-- Poops -->
  ${poopsSVG}

  <!-- Rats -->
  ${ratsSVG}

  <!-- Cat -->
  ${catSVG}
</svg>`;
}

// ---- index.ts ----
const fs = require("fs");
const path = require("path");

async function main() {
  const args = process.argv.slice(2);
  const getArg = (flag, def) => {
    const idx = args.indexOf(flag);
    if (idx !== -1 && args[idx + 1]) return args[idx + 1];
    return def;
  };

  const username = getArg("--username", process.env.GITHUB_USER_NAME);
  const token    = getArg("--token",    process.env.GITHUB_TOKEN);
  const theme    = getArg("--theme",    "github");
  const output   = getArg("--output",   "dist/cat-contribution-graph.svg");

  if (!username) { console.error("Error: --username required"); process.exit(1); }
  if (!token)    { console.error("Error: --token required (or GITHUB_TOKEN env)"); process.exit(1); }

  console.log(`🐱 Fetching contributions for ${username}...`);
  const graph = await fetchContributionGraph(username, token);
  console.log(`📊 ${graph.totalContributions} contributions, ${graph.weeks.length} weeks`);

  const svg = generateCatSVG(graph, username, theme);

  const outDir = path.dirname(output);
  if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true });
  fs.writeFileSync(output, svg, "utf-8");
  console.log(`✅ Saved: ${output}`);
}

main().catch(err => { console.error(err); process.exit(1); });
